#!/usr/bin/env bash
# This file was generated by Cursor AI on 2026-05-12.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
SLURM_OUTPUT_DIR="$SCRIPT_DIR"
GUROBI_LIC_PATH=""
BENCHMARK_SIF_PATH=""
RESULTS_OUTPUT_DIR=""
INPUT_FILE_LIST=""

print_usage() {
  cat <<'EOF'
Usage: ./generate_slurm_benchmarks_txt.sh \
  --benchmark-sif PATH \
  --input-file-list PATH \
  --output-dir DIR \
  [--gurobi-lic PATH] \
  [--slurm-output-dir DIR]

Generate five eqsat SLURM scripts (one job per mode), all using the same
benchmark list file:

  control.slurm
  ilp_ac.slurm
  ilp_no_ac.slurm
  greedy_ac.slurm
  greedy_no_ac.slurm

Each script writes JSON to <output-dir>/<mode>.json (e.g. control.json, ilp_ac.json).

Options:
  --gurobi-lic PATH       Optional path to local gurobi.lic file (host path)
  --benchmark-sif PATH    Path to benchmark.sif file
  --input-file-list PATH  Text file with one input path per line (passed to --input-file-list)
  --output-dir DIR        Directory for output JSON files written by benchmark.sif
  --slurm-output-dir DIR  Directory to write generated .slurm files (default: script directory)
  -h, --help              Show this help
EOF
}

while [[ $# -gt 0 ]]; do
  case "$1" in
    --gurobi-lic)
      GUROBI_LIC_PATH="${2:-}"
      shift 2
      ;;
    --benchmark-sif)
      BENCHMARK_SIF_PATH="${2:-}"
      shift 2
      ;;
    --input-file-list)
      INPUT_FILE_LIST="${2:-}"
      shift 2
      ;;
    --output-dir)
      RESULTS_OUTPUT_DIR="${2:-}"
      shift 2
      ;;
    --slurm-output-dir)
      SLURM_OUTPUT_DIR="${2:-}"
      shift 2
      ;;
    -h|--help)
      print_usage
      exit 0
      ;;
    *)
      echo "Unknown option: $1" >&2
      print_usage >&2
      exit 1
      ;;
  esac
done

if [[ -z "$BENCHMARK_SIF_PATH" || -z "$INPUT_FILE_LIST" || -z "$RESULTS_OUTPUT_DIR" ]]; then
  echo "Missing required arguments." >&2
  print_usage >&2
  exit 1
fi

if [[ -n "$GUROBI_LIC_PATH" && ! -f "$GUROBI_LIC_PATH" ]]; then
  echo "gurobi.lic not found: $GUROBI_LIC_PATH" >&2
  exit 1
fi

if [[ ! -f "$BENCHMARK_SIF_PATH" ]]; then
  echo "benchmark.sif not found: $BENCHMARK_SIF_PATH" >&2
  exit 1
fi

if [[ ! -f "$INPUT_FILE_LIST" ]]; then
  echo "Input file list not found: $INPUT_FILE_LIST" >&2
  exit 1
fi

mkdir -p "$RESULTS_OUTPUT_DIR"
mkdir -p "$SLURM_OUTPUT_DIR"

APPTAINER_BIND_ARGS=()
if [[ -n "$GUROBI_LIC_PATH" ]]; then
  APPTAINER_BIND_ARGS=(--bind "${GUROBI_LIC_PATH}:/root/gurobi.lic")
fi

write_slurm() {
  local mode_name="$1"
  local extraction_method="$2"
  local assoc_comm_flag="$3"
  local use_control="${4:-0}"

  local job_name="$mode_name"
  local output_file="$SLURM_OUTPUT_DIR/${job_name}.slurm"
  local output_json="${RESULTS_OUTPUT_DIR}/${job_name}.json"

  cat > "$output_file" <<EOF
#!/bin/bash

# Copy/paste this job script into a text file and submit with the command:
#    sbatch thefilename
# Job standard output will go to the file slurm-%j.out (where %j is the job ID)

#SBATCH --nodes=1   # Number of nodes to use
#SBATCH --ntasks-per-node=20   # Use 20 processor cores per node 
#SBATCH --time=2-0:0:0   # Walltime limit (DD-HH:MM:SS)
#SBATCH --mem=0   # Maximum memory per node

# LOAD MODULES, INSERT CODE, AND RUN YOUR PROGRAMS HERE
module load apptainer
apptainer run ${APPTAINER_BIND_ARGS[@]+"${APPTAINER_BIND_ARGS[@]}"} "${BENCHMARK_SIF_PATH}" \\
  --input-file-list "${INPUT_FILE_LIST}" \\
  --output-json "${output_json}" \\
EOF

  if [[ "$use_control" == "1" ]]; then
    echo "  --control \\" >> "$output_file"
  fi

  cat >> "$output_file" <<EOF
  --timeout "3600" \\
  --memout "64000" \\
  --num-gurobi-threads "0" \\
  --num-jobs "20" \\
  --extraction-method "${extraction_method}" \\
  --multi-arity \\
  ${assoc_comm_flag}
EOF

  echo "Wrote: $output_file"
}

write_slurm "control" "ilp" "--assoc-comm" "1"
write_slurm "ilp_ac" "ilp" "--assoc-comm" "0"
write_slurm "ilp_no_ac" "ilp" "--no-assoc-comm" "0"
write_slurm "greedy_ac" "greedy" "--assoc-comm" "0"
write_slurm "greedy_no_ac" "greedy" "--no-assoc-comm" "0"
